function [nmbImg,imgLst] = fImgLstV01(inpDir,fName)%% Function to get a list of existing image nad  shot number, ver.1%% [nmbImg,imgLst,nameLst] = fImgLstV01(inpDir,fName)%% inpDir: directory to look for images% fName: part of the name of the images, like 'OTR'% nmbImg: number of image exist% imgLst: list of the name of images%% Kei Nakamura% Created on Friday, August 14th 2009.% Modified on Friday, June 11th 2010.%%imgLst = dir([inpDir,'/Scan*',fName,'*.png']);  % image listbgLst = dir([inpDir,'/Scan*',fName,'BG*.png']);  % image listbgL = numel(bgLst(1).name); % length of bg namenameL = zeros(numel(imgLst),1);   % allocationfor ii=1:numel(imgLst);    nameL(ii) = numel(imgLst(ii).name); % name lengthendk = find(nameL~=bgL);   imgLst = imgLst(k); % select non-background imagenmbImg = numel(imgLst);
